package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.BackupCodeRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
@RequiredArgsConstructor
@Slf4j
public class BackupCodeService {

    private static final int BACKUP_CODE_COUNT = 10;
    private static final int BACKUP_CODE_LENGTH = 8;
    private static final String BACKUP_CODE_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    private static final int LOW_BACKUP_CODE_THRESHOLD = 3;

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    @Transactional
    public List<String> generateBackupCodes(User user) {
        // Remove existing backup codes
        backupCodeRepository.deleteAllByUser(user);
        backupCodeRepository.flush();

        List<String> plainTextCodes = new ArrayList<>();
        List<BackupCode> backupCodes = new ArrayList<>();

        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String code = generateRandomCode();
            String formattedCode = formatCode(code);
            plainTextCodes.add(formattedCode);

            BackupCode backupCode = BackupCode.builder()
                    .codeHash(passwordEncoder.encode(code.toUpperCase().replace("-", "")))
                    .user(user)
                    .used(false)
                    .build();
            backupCodes.add(backupCode);
        }

        backupCodeRepository.saveAll(backupCodes);
        log.info("Generated {} backup codes for user: {}", BACKUP_CODE_COUNT, user.getUsername());

        return plainTextCodes;
    }

    @Transactional
    public boolean validateAndConsumeBackupCode(User user, String code) {
        String normalizedCode = code.toUpperCase().replace("-", "").replace(" ", "");
        List<BackupCode> unusedCodes = backupCodeRepository.findByUserAndUsedFalse(user);

        for (BackupCode backupCode : unusedCodes) {
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);

                long remaining = backupCodeRepository.countByUserAndUsedFalse(user);
                log.info("Backup code consumed for user: {}. Remaining codes: {}", user.getUsername(), remaining);

                if (remaining <= LOW_BACKUP_CODE_THRESHOLD) {
                    log.warn("User {} has only {} backup codes remaining. Consider regenerating.", user.getUsername(), remaining);
                }

                return true;
            }
        }

        log.warn("Invalid backup code attempt for user: {}", user.getUsername());
        return false;
    }

    public long getRemainingCodesCount(User user) {
        return backupCodeRepository.countByUserAndUsedFalse(user);
    }

    public boolean shouldRegenerateCodes(User user) {
        return getRemainingCodesCount(user) <= LOW_BACKUP_CODE_THRESHOLD;
    }

    private String generateRandomCode() {
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < BACKUP_CODE_LENGTH; i++) {
            code.append(BACKUP_CODE_CHARS.charAt(secureRandom.nextInt(BACKUP_CODE_CHARS.length())));
        }
        return code.toString();
    }

    private String formatCode(String code) {
        // Format as XXXX-XXXX for readability
        if (code.length() == BACKUP_CODE_LENGTH) {
            return code.substring(0, 4) + "-" + code.substring(4);
        }
        return code;
    }
}

// src/main/java/com/enterprise/auth/service/TotpService.java
package com.enterprise.auth.service;

import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Service
@Slf4j
public class TotpService {

    private static final int SECRET_LENGTH = 20;
    private static final int CODE_DIGITS = 6;
    private static final int TIME_STEP_SECONDS = 30;
    private static final int TIME_WINDOW = 1; // Allow 1 step before/after
    private static final String HMAC_ALGORITHM = "HmacSHA1";
    private static final String BASE32_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

    private final SecureRandom secureRandom = new SecureRandom();

    public String generateSecret() {
        byte[] bytes = new byte[SECRET_LENGTH];
        secureRandom.nextBytes(bytes);
        return base32Encode(bytes);
    }

    public boolean verifyCode(String secret, String code) {
        if (code == null || code.length() != CODE_DIGITS) {
            return false;
        }

        try {
            int codeInt = Integer.parseInt(code);
            long currentTimeStep = Instant.now().getEpochSecond() / TIME_STEP_SECONDS;

            for (int i = -TIME_WINDOW; i <= TIME_WINDOW; i++) {
                int generatedCode = generateCode(secret, currentTimeStep + i);
                if (generatedCode == codeInt) {
                    return true;
                }
            }
        } catch (NumberFormatException e) {
            log.warn("Invalid TOTP code format");
        }

        return false;
    }

    public String getQrCodeUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP_SECONDS);
    }

    private int generateCode(String secret, long timeStep) {
        try {
            byte[] key = base32Decode(secret);
            byte[] data = ByteBuffer.allocate(8).putLong(timeStep).array();

            Mac mac = Mac.getInstance(HMAC_ALGORITHM);
            mac.init(new SecretKeySpec(key, HMAC_ALGORITHM));
            byte[] hash = mac.doFinal(data);

            int offset = hash[hash.length - 1] & 0x0F;
            int truncatedHash = ((hash[offset] & 0x7F) << 24)
                    | ((hash[offset + 1] & 0xFF) << 16)
                    | ((hash[offset + 2] & 0xFF) << 8)
                    | (hash[offset + 3] & 0xFF);

            return truncatedHash % (int) Math.pow(10, CODE_DIGITS);
        } catch (Exception e) {
            throw new RuntimeException("Error generating TOTP code", e);
        }
    }

    private String base32Encode(byte[] data) {
        StringBuilder result = new StringBuilder();
        int buffer = 0;
        int bitsLeft = 0;

        for (byte b : data) {
            buffer = (buffer << 8) | (b & 0xFF);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                result.append(BASE32_CHARS.charAt((buffer >> (bitsLeft - 5)) & 0x1F));
                bitsLeft -= 5;
            }
        }

        if (bitsLeft > 0) {
            result.append(BASE32_CHARS.charAt((buffer << (5 - bitsLeft)) & 0x1F));
        }

        return result.toString();
    }

    private byte[] base32Decode(String encoded) {
        encoded = encoded.toUpperCase().replaceAll("[^A-Z2-7]", "");
        int outputLength = encoded.length() * 5 / 8;
        byte[] result = new byte[outputLength];
        int buffer = 0;
        int bitsLeft = 0;
        int index = 0;

        for (char c : encoded.toCharArray()) {
            int val = BASE32_CHARS.indexOf(c);
            if (val < 0) continue;
            buffer = (buffer << 5) | val;
            bitsLeft += 5;
            if (bitsLeft >= 8) {
                result[index++] = (byte) (buffer >> (bitsLeft - 8));
                bitsLeft -= 8;
            }
        }

        return result;
    }
}

