package com.enterprise.auth.service;

import com.enterprise.auth.entity.AuthenticationAuditLog;
import com.enterprise.auth.repository.AuthenticationAuditLogRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;

@Service
@RequiredArgsConstructor
@Slf4j
public class AuditService {

    private final AuthenticationAuditLogRepository auditLogRepository;

    private static final int MAX_FAILED_ATTEMPTS = 5;
    private static final int LOCKOUT_MINUTES = 15;

    @Transactional
    public void logAuthenticationAttempt(Long userId, String username, String authMethod,
                                         String status, String ipAddress, String userAgent,
                                         String failureReason) {
        AuthenticationAuditLog auditLog = AuthenticationAuditLog.builder()
                .userId(userId)
                .username(username)
                .authMethod(authMethod)
                .status(status)
                .ipAddress(ipAddress)
                .userAgent(userAgent)
                .failureReason(failureReason)
                .build();

        auditLogRepository.save(auditLog);
        log.info("Auth audit: user={}, method={}, status={}, ip={}", username, authMethod, status, ipAddress);
    }

    public boolean isAccountLocked(Long userId) {
        LocalDateTime lockoutThreshold = LocalDateTime.now().minusMinutes(LOCKOUT_MINUTES);
        long failedAttempts = auditLogRepository.countByUserIdAndStatusAndCreatedAtAfter(
                userId, "FAILED", lockoutThreshold);
        return failedAttempts >= MAX_FAILED_ATTEMPTS;
    }
}

