package com.enterprise.auth.service;

import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;

@Service
@Slf4j
public class JwtService {

    @Value("${jwt.secret:myVerySecretKeyThatIsAtLeast256BitsLongForHS256Algorithm123}")
    private String jwtSecret;

    @Value("${jwt.expiration:3600000}")
    private long jwtExpiration;

    @Value("${jwt.mfa-token.expiration:300000}")
    private long mfaTokenExpiration;

    public String generateToken(String username, boolean fullyAuthenticated) {
        Map<String, Object> claims = new HashMap<>();
        claims.put("fullyAuthenticated", fullyAuthenticated);
        return buildToken(claims, username, jwtExpiration);
    }

    public String generateMfaPendingToken(String username) {
        Map<String, Object> claims = new HashMap<>();
        claims.put("mfaPending", true);
        claims.put("fullyAuthenticated", false);
        return buildToken(claims, username, mfaTokenExpiration);
    }

    public String extractUsername(String token) {
        return parseClaims(token).getSubject();
    }

    public boolean isTokenValid(String token) {
        try {
            Claims claims = parseClaims(token);
            return !claims.getExpiration().before(new Date());
        } catch (JwtException e) {
            log.warn("Invalid JWT token: {}", e.getMessage());
            return false;
        }
    }

    public boolean isMfaPendingToken(String token) {
        try {
            Claims claims = parseClaims(token);
            Boolean mfaPending = claims.get("mfaPending", Boolean.class);
            return mfaPending != null && mfaPending;
        } catch (JwtException e) {
            return false;
        }
    }

    public boolean isFullyAuthenticated(String token) {
        try {
            Claims claims = parseClaims(token);
            Boolean fullyAuthenticated = claims.get("fullyAuthenticated", Boolean.class);
            return fullyAuthenticated != null && fullyAuthenticated;
        } catch (JwtException e) {
            return false;
        }
    }

    private String buildToken(Map<String, Object> claims, String subject, long expiration) {
        return Jwts.builder()
                .claims(claims)
                .subject(subject)
                .issuedAt(new Date())
                .expiration(new Date(System.currentTimeMillis() + expiration))
                .signWith(getSigningKey())
                .compact();
    }

    private Claims parseClaims(String token) {
        return Jwts.parser()
                .verifyWith(getSigningKey())
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    private SecretKey getSigningKey() {
        return Keys.hmacShaKeyFor(jwtSecret.getBytes(StandardCharsets.UTF_8));
    }
}

