package com.enterprise.auth.service;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.*;
import com.enterprise.auth.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
@RequiredArgsConstructor
@Slf4j
public class AuthenticationService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;
    private final JwtService jwtService;
    private final AuditService auditService;

    @Transactional
    public ApiResponse<AuthResponse> register(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new UserAlreadyExistsException("Username already taken: " + request.getUsername());
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new UserAlreadyExistsException("Email already registered: " + request.getEmail());
        }

        User user = User.builder()
                .username(request.getUsername())
                .email(request.getEmail())
                .password(passwordEncoder.encode(request.getPassword()))
                .mfaEnabled(false)
                .build();

        userRepository.save(user);
        log.info("User registered: {}", user.getUsername());

        String token = jwtService.generateToken(user.getUsername(), true);

        AuthResponse response = AuthResponse.builder()
                .token(token)
                .username(user.getUsername())
                .mfaRequired(false)
                .message("Registration successful")
                .build();

        return ApiResponse.success("User registered successfully", response);
    }

    @Transactional
    public ApiResponse<AuthResponse> login(LoginRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationFailedException("Invalid username or password"));

        if (auditService.isAccountLocked(user.getId())) {
            auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                    "PASSWORD", "LOCKED", ipAddress, userAgent, "Account locked due to too many failed attempts");
            throw new AccountLockedException("Account is temporarily locked. Please try again later.");
        }

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                    "PASSWORD", "FAILED", ipAddress, userAgent, "Invalid password");
            throw new AuthenticationFailedException("Invalid username or password");
        }

        if (user.isMfaEnabled()) {
            String mfaToken = jwtService.generateMfaPendingToken(user.getUsername());
            auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                    "PASSWORD", "MFA_PENDING", ipAddress, userAgent, null);

            AuthResponse response = AuthResponse.builder()
                    .mfaRequired(true)
                    .mfaToken(mfaToken)
                    .username(user.getUsername())
                    .message("MFA verification required. Use TOTP code or backup code.")
                    .build();

            return ApiResponse.success("Password verified. MFA required.", response);
        }

        String token = jwtService.generateToken(user.getUsername(), true);
        auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                "PASSWORD", "SUCCESS", ipAddress, userAgent, null);

        AuthResponse response = AuthResponse.builder()
                .token(token)
                .username(user.getUsername())
                .mfaRequired(false)
                .message("Login successful")
                .build();

        return ApiResponse.success("Login successful", response);
    }

    @Transactional
    public ApiResponse<AuthResponse> verifyMfa(MfaVerificationRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationFailedException("User not found"));

        if (auditService.isAccountLocked(user.getId())) {
            throw new AccountLockedException("Account is temporarily locked.");
        }

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        boolean valid = totpService.verifyCode(user.getMfaSecret(), request.getCode());

        if (!valid) {
            auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                    "TOTP", "FAILED", ipAddress, userAgent, "Invalid TOTP code");
            throw new AuthenticationFailedException("Invalid MFA code");
        }

        String token = jwtService.generateToken(user.getUsername(), true);
        auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                "TOTP", "SUCCESS", ipAddress, userAgent, null);

        AuthResponse response = AuthResponse.builder()
                .token(token)
                .username(user.getUsername())
                .mfaRequired(false)
                .message("MFA verification successful")
                .build();

        return ApiResponse.success("MFA verification successful", response);
    }

    @Transactional
    public ApiResponse<AuthResponse> authenticateWithBackupCode(BackupCodeAuthRequest request,
                                                                  String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationFailedException("User not found"));

        if (auditService.isAccountLocked(user.getId())) {
            throw new AccountLockedException("Account is temporarily locked.");
        }

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        boolean valid = backupCodeService.validateAndConsumeBackupCode(user, request.getBackupCode());

        if (!valid) {
            auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                    "BACKUP_CODE", "FAILED", ipAddress, userAgent, "Invalid backup code");
            throw new AuthenticationFailedException("Invalid backup code");
        }

        String token = jwtService.generateToken(user.getUsername(), true);
        long remainingCodes = backupCodeService.getRemainingCodesCount(user);

        auditService.logAuthenticationAttempt(user.getId(), user.getUsername(),
                "BACKUP_CODE", "SUCCESS", ipAddress, userAgent, null);

        String message = String.format("Backup code authentication successful. %d backup codes remaining.", remainingCodes);
        if (backupCodeService.shouldRegenerateCodes(user)) {
            message += " WARNING: You are running low on backup codes. Please generate new ones.";
        }

        AuthResponse response = AuthResponse.builder()
                .token(token)
                .username(user.getUsername())
                .mfaRequired(false)
                .message(message)
                .build();

        return ApiResponse.success("Backup code authentication successful", response);
    }

    @Transactional
    public ApiResponse<MfaSetupResponse> initiateMfaSetup(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this account");
        }

        String secret = totpService.generateSecret();
        user.setMfaSecret(secret);
        userRepository.save(user);

        String qrCodeUri = totpService.getQrCodeUri(secret, user.getUsername(), "EnterpriseAuth");

        MfaSetupResponse response = MfaSetupResponse.builder()
                .secret(secret)
                .qrCodeUri(qrCodeUri)
                .message("Scan the QR code with your authenticator app, then verify with a code to enable MFA")
                .build();

        return ApiResponse.success("MFA setup initiated", response);
    }

    @Transactional
    public ApiResponse<MfaSetupResponse> confirmMfaSetup(String username, EnableMfaRequest request) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled");
        }

        if (user.getMfaSecret() == null) {
            throw new MfaException("MFA setup not initiated. Please initiate setup first.");
        }

        boolean valid = totpService.verifyCode(user.getMfaSecret(), request.getVerificationCode());
        if (!valid) {
            throw new MfaException("Invalid verification code. Please try again.");
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        log.info("MFA enabled for user: {}", username);

        MfaSetupResponse response = MfaSetupResponse.builder()
                .backupCodes(backupCodes)
                .message("MFA enabled successfully. Save your backup codes in a secure location. " +
                        "These codes can be used to access your account if you lose your MFA device.")
                .build();

        return ApiResponse.success("MFA enabled successfully", response);
    }

    @Transactional
    public ApiResponse<Void> disableMfa(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        user.getBackupCodes().clear();
        userRepository.save(user);

        log.info("MFA disabled for user: {}", username);

        return ApiResponse.success("MFA disabled successfully");
    }

    @Transactional
    public ApiResponse<MfaSetupResponse> regenerateBackupCodes(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA must be enabled to generate backup codes");
        }

        List<String> newBackupCodes = backupCodeService.generateBackupCodes(user);

        log.info("Backup codes regenerated for user: {}", username);

        MfaSetupResponse response = MfaSetupResponse.builder()
                .backupCodes(newBackupCodes)
                .message("New backup codes generated. Previous codes are now invalid. " +
                        "Save these codes in a secure location.")
                .build();

        return ApiResponse.success("Backup codes regenerated successfully", response);
    }

    public ApiResponse<BackupCodeStatusResponse> getBackupCodeStatus(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        long remaining = backupCodeService.getRemainingCodesCount(user);
        long total = user.getBackupCodes().size();

        BackupCodeStatusResponse response = BackupCodeStatusResponse.builder()
                .totalCodes(total)
                .remainingCodes(remaining)
                .usedCodes(total - remaining)
                .shouldRegenerate(backupCodeService.shouldRegenerateCodes(user))
                .build();

        return ApiResponse.success("Backup code status retrieved", response);
    }
}

