package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.AuthenticationService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
@RequiredArgsConstructor
public class MfaController {

    private final AuthenticationService authenticationService;

    @PostMapping("/setup/initiate")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> initiateMfaSetup(Authentication authentication) {
        return ResponseEntity.ok(authenticationService.initiateMfaSetup(authentication.getName()));
    }

    @PostMapping("/setup/confirm")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> confirmMfaSetup(
            Authentication authentication,
            @Valid @RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(authenticationService.confirmMfaSetup(authentication.getName(), request));
    }

    @PostMapping("/disable")
    public ResponseEntity<ApiResponse<Void>> disableMfa(Authentication authentication) {
        return ResponseEntity.ok(authenticationService.disableMfa(authentication.getName()));
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> regenerateBackupCodes(Authentication authentication) {
        return ResponseEntity.ok(authenticationService.regenerateBackupCodes(authentication.getName()));
    }

    @GetMapping("/backup-codes/status")
    public ResponseEntity<ApiResponse<BackupCodeStatusResponse>> getBackupCodeStatus(Authentication authentication) {
        return ResponseEntity.ok(authenticationService.getBackupCodeStatus(authentication.getName()));
    }
}

